}

public void testHash32x86WithTrailingNegativeSignedBytes() {
    Assert.assertEquals(-43192051, MurmurHash3.hash32x861(new byte[] {-1}, 0, 1, 0));
    Assert.assertEquals(-582037868, MurmurHash3.hash32x861(new byte[] {0, -1}, 0, 2, 0));
    Assert.assertEquals(922088087, MurmurHash3.hash32x861(new byte[] {0, 0, -1}, 0, 3, 0));
    Assert.assertEquals(-1309567588, MurmurHash3.hash32x861(new byte[] {-1, 0}, 0, 2, 0));
    Assert.assertEquals(-363779670, MurmurHash3.hash32x861(new byte[] {-1, 0, 0}, 0, 3, 0));
    Assert.assertEquals(-225068062, MurmurHash3.hash32x861(new byte[] {0, -1, 0}, 0, 3, 0));
}

public void testHash32WithTrailingNegativeSignedBytesIsInvalid() {
    Assert.assertNotEquals(-43192051, MurmurHash3.hash328(new byte[] {-1}, 0, 1, 0));
    Assert.assertNotEquals(-582037868, MurmurHash3.hash328(new byte[] {0, -1}, 0, 2, 0));
    Assert.assertNotEquals(922088087, MurmurHash3.hash328(new byte[] {0, 0, -1}, 0, 3, 0));
    Assert.assertNotEquals(-1309567588, MurmurHash3.hash328(new byte[] {-1, 0}, 0, 2, 0));
    Assert.assertNotEquals(-363779670, MurmurHash3.hash328(new byte[] {-1, 0, 0}, 0, 3, 0));
    Assert.assertNotEquals(-225068062, MurmurHash3.hash328(new byte[] {0, -1, 0}, 0, 3, 0));
}

